const value2 = "" || "Mặc định";
console.log('"" || "Mặc định" =', value2); // "Mặc định"

// Nullish Coalescing (??): Chỉ thay thế null/undefined
const value3 = 0 ?? 100;
console.log("0 ?? 100 =", value3); // 0 (giữ nguyên)

const value4 = "" ?? "Mặc định";
console.log('"" ?? "Mặc định" =', value4); // "" (giữ nguyên)

// Ứng dụng thực tế
const userInput = 0; // Người dùng nhập số 0
const quantity = userInput ?? 1; // Giữ 0, không thay bằng 1
console.log("Số lượng:", quantity);

