// Mô phỏng API có thể lỗi
const fetchData = (shouldFail) => {
  return new Promise((resolve, reject) => {
    setTimeout(() => {
      if (shouldFail) {
        reject(new Error("Lỗi kết nối!"));
      } else {
        resolve({ data: "Thành công" });
      }
    }, 500);
  });
};

// Xử lý lỗi với try/catch
async function loadData(shouldFail) {
  try {
    console.log("Đang tải...");
    const result = await fetchData(shouldFail);
    console.log("Kết quả:", result);
  } catch (error) {
    console.log("❌ Lỗi:", error.message);
  } finally {
    console.log("Hoàn thành (dù lỗi hay không)");
  }
}

// Test
loadData(false); // Thành công
setTimeout(() => loadData(true), 1500); // Lỗi

