// Closure: Hàm con "nhớ" được biến của hàm cha
// Ngay cả khi hàm cha đã chạy xong!

function createCounter() {
  let count = 0;  // Biến private

  return function() {
    count++;
    return count;
  };
}

const counter1 = createCounter();
const counter2 = createCounter();

console.log("=== CLOSURE DEMO ===");
console.log("counter1():", counter1()); // 1
console.log("counter1():", counter1()); // 2
console.log("counter1():", counter1()); // 3

console.log("counter2():", counter2()); // 1 - Độc lập!
console.log("counter2():", counter2()); // 2

// Ứng dụng thực tế: Private variables
function createUser(name) {
  let password = "secret123";  // Private

  return {
    getName: () => name,
    checkPassword: (input) => input === password
  };
}

const user = createUser("Huy");
console.log("");
console.log("=== PRIVATE VARIABLES ===");
console.log("Name:", user.getName());
console.log("Check password:", user.checkPassword("secret123"));
