// Method Chaining: Xử lý dữ liệu như dây chuyền sản xuất

const users = [
  { name: "Huy", age: 17, score: 85, active: true },
  { name: "Lan", age: 25, score: 92, active: true },
  { name: "Nam", age: 30, score: 78, active: false },
  { name: "Mai", age: 22, score: 95, active: true },
  { name: "Tú", age: 19, score: 65, active: true }
];

// Pipeline: Lọc -> Biến đổi -> Tính toán
const result = users
  .filter(u => u.active)           // Bước 1: Lọc user active
  .filter(u => u.age >= 18)        // Bước 2: Lọc người lớn
  .map(u => u.score)               // Bước 3: Lấy điểm
  .reduce((sum, score) => sum + score, 0); // Bước 4: Tính tổng

console.log("=== DATA PIPELINE ===");
console.log("Tổng điểm (active, >=18):", result);

