  .filter(u => u.active)
  .filter(u => u.score >= 80)
  .map(u => ({ name: u.name, grade: u.score >= 90 ? "A" : "B" }))
  .sort((a, b) => b.grade.localeCompare(a.grade));

console.log("");
console.log("=== TOP USERS ===");
topUsers.forEach(u => console.log(`${u.name}: ${u.grade}`));

