// Type Casting: Chuyển đổi giữa các kiểu dữ liệu

#include <iostream>
using namespace std;

int main() {
    cout << "=== TYPE CASTING ===" << endl;
    cout << endl;

    // Implicit Casting (Tự động)
    int x = 10;
    double y = x;  // int -> double (an toàn)
    cout << "x (int): " << x << endl;
    cout << "y (double): " << y << endl;
    cout << endl;

    // Explicit Casting (Tường minh)
    double pi = 3.14159;
    int piInt = (int)pi;  // Mất phần thập phân!
    cout << "pi (double): " << pi << endl;
    cout << "piInt (int): " << piInt << endl;
    cout << endl;

    // C++ style casting
    double price = 99.99;
    int priceInt = static_cast<int>(price);
    cout << "price: " << price << endl;
    cout << "priceInt: " << priceInt << endl;
    cout << endl;

    cout << "Lưu ý:" << endl;
    cout << "- Ép từ lớn -> nhỏ: Mất dữ liệu" << endl;
    cout << "- Ép từ nhỏ -> lớn: An toàn" << endl;

    return 0;
}

