            break;
        default:
            cout << "Lựa chọn không hợp lệ" << endl;
    }
    cout << endl;

    cout << "Khi nào dùng switch?" << endl;
    cout << "- Nhiều điều kiện so sánh bằng (==)" << endl;
    cout << "- Nhanh hơn if/else khi có nhiều case" << endl;
    cout << "- Dễ đọc hơn với menu lựa chọn" << endl;

