// Vòng lặp: while và for

#include <iostream>
using namespace std;

int main() {
    cout << "=== VÒNG LẶP WHILE ===" << endl;
    int count = 0;
    while (count < 3) {
        cout << "Count: " << count << endl;
        count++;
    }
    cout << endl;

    cout << "=== VÒNG LẶP FOR ===" << endl;
    for (int i = 0; i < 3; i++) {
        cout << "i: " << i << endl;
    }
    cout << endl;

    cout << "=== DO-WHILE (Chạy ít nhất 1 lần) ===" << endl;
    int x = 0;
    do {
        cout << "x: " << x << endl;
        x++;
    } while (x < 3);
    cout << endl;

    cout << "Khi nào dùng gì?" << endl;
    cout << "- for: Biết trước số lần lặp" << endl;
    cout << "- while: Không biết trước số lần lặp" << endl;
    cout << "- do-while: Cần chạy ít nhất 1 lần" << endl;

    return 0;
}

