// break: Thoát vòng lặp
// continue: Bỏ qua lần lặp hiện tại

#include <iostream>
using namespace std;

int main() {
    cout << "=== BREAK ===" << endl;
    for (int i = 0; i < 10; i++) {
        if (i == 5) {
            cout << "Gặp 5, thoát!" << endl;
            break;  // Thoát vòng lặp
        }
        cout << "i: " << i << endl;
    }
    cout << endl;

    cout << "=== CONTINUE ===" << endl;
    for (int i = 0; i < 5; i++) {
        if (i == 2) {
            cout << "Bỏ qua 2" << endl;
            continue;  // Bỏ qua, nhảy sang lần lặp tiếp
        }
        cout << "i: " << i << endl;
    }
    cout << endl;

    cout << "=== ỨNG DỤNG ===" << endl;
    cout << "Tìm số chẵn đầu tiên > 10:" << endl;
    for (int i = 0; i < 20; i++) {
        if (i % 2 != 0) continue;  // Bỏ qua số lẻ
        if (i > 10) {
            cout << "Tìm thấy: " << i << endl;
            break;
        }
    }

    return 0;
}

