// Pass by Reference: Không copy, dùng trực tiếp biến gốc

#include <iostream>
using namespace std;

void increment(int& x) {  // & = reference
    x = x + 1;
    cout << "Trong hàm: x = " << x << endl;
}

void swap(int& a, int& b) {
    int temp = a;
    a = b;
    b = temp;
}

int main() {
    cout << "=== PASS BY REFERENCE ===" << endl;
    cout << endl;

    int num = 10;
    cout << "Trước: num = " << num << endl;

    increment(num);  // Truyền reference

    cout << "Sau: num = " << num << endl;
    cout << endl;

    cout << "=== SWAP ===" << endl;
    int x = 5, y = 10;
    cout << "Trước: x = " << x << ", y = " << y << endl;
    swap(x, y);
    cout << "Sau: x = " << x << ", y = " << y << endl;
    cout << endl;

    cout << "Ưu điểm:" << endl;
    cout << "- Không copy, tiết kiệm bộ nhớ" << endl;
    cout << "- Nhanh hơn" << endl;
