// Pointer (*) vs Reference (&)

#include <iostream>
using namespace std;

int main() {
    cout << "=== POINTER vs REFERENCE ===" << endl;
    cout << endl;

    int age = 25;

    // Reference (Tham chiếu)
    int& ref = age;  // Phải khởi tạo ngay

    // Pointer (Con trỏ)
    int* ptr = &age;  // Có thể khởi tạo sau

    cout << "Giá trị ban đầu:" << endl;
    cout << "age = " << age << endl;
    cout << "ref = " << ref << endl;
    cout << "*ptr = " << *ptr << endl;
    cout << endl;

    // Thay đổi qua reference
    ref = 30;
    cout << "Sau ref = 30:" << endl;
    cout << "age = " << age << endl;
    cout << endl;

    // Thay đổi qua pointer
    *ptr = 35;
    cout << "Sau *ptr = 35:" << endl;
    cout << "age = " << age << endl;
    cout << endl;

    cout << "So sánh:" << endl;
    cout << "REFERENCE:" << endl;
    cout << "- Phải khởi tạo ngay" << endl;
    cout << "- Không thể null" << endl;
    cout << "- Không thể đổi trỏ sang biến khác" << endl;
    cout << "- An toàn hơn" << endl;
    cout << endl;
    cout << "POINTER:" << endl;
    cout << "- Có thể khởi tạo sau" << endl;
    cout << "- Có thể null" << endl;
    cout << "- Có thể đổi trỏ sang biến khác" << endl;
    cout << "- Linh hoạt hơn" << endl;

    return 0;
}

