// Pointer Arithmetic: Cộng trừ con trỏ

#include <iostream>
using namespace std;

int main() {
    cout << "=== POINTER ARITHMETIC ===" << endl;
    cout << endl;

    int arr[5] = {10, 20, 30, 40, 50};
    int* ptr = arr;

    cout << "Duyệt mảng bằng con trỏ:" << endl;
    for (int i = 0; i < 5; i++) {
        cout << "*(ptr + " << i << ") = " << *(ptr + i) << endl;
    }
    cout << endl;

    cout << "Tăng con trỏ:" << endl;
    ptr = arr;
    cout << "*ptr = " << *ptr << endl;
    ptr++;  // Nhảy sang phần tử tiếp theo
    cout << "*ptr sau ptr++ = " << *ptr << endl;
    ptr += 2;  // Nhảy 2 phần tử
    cout << "*ptr sau ptr+=2 = " << *ptr << endl;
    cout << endl;

    cout << "Khoảng cách:" << endl;
    int* start = arr;
    int* end = arr + 4;
    cout << "end - start = " << (end - start) << " phần tử" << endl;
    cout << endl;

    cout << "Lưu ý:" << endl;
    cout << "ptr + 1 không phải +1 byte!" << endl;
    cout << "ptr + 1 = ptr + sizeof(int) bytes" << endl;

    return 0;
}

