    cout << "- Kích thước cố định" << endl;
    cout << "- Khó thao tác" << endl;
    cout << "- Nguy hiểm (buffer overflow)" << endl;
    cout << endl;
    cout << "STD::STRING:" << endl;
    cout << "- Object, quản lý tự động" << endl;
    cout << "- Kích thước động" << endl;
    cout << "- Nhiều method tiện lợi" << endl;
    cout << "- An toàn hơn" << endl;

