// Stack vs Heap: 2 vùng nhớ khác nhau

#include <iostream>
using namespace std;

int main() {
    cout << "=== STACK vs HEAP ===" << endl;
    cout << endl;

    // STACK: Tự động quản lý
    int stackVar = 10;
    cout << "Stack variable: " << stackVar << endl;
    cout << "Địa chỉ: " << &stackVar << endl;
    cout << endl;

    // HEAP: Quản lý thủ công
    int* heapVar = new int(20);
    cout << "Heap variable: " << *heapVar << endl;
    cout << "Địa chỉ: " << heapVar << endl;
    delete heapVar;  // Phải xóa thủ công!
    cout << endl;

    cout << "STACK:" << endl;
    cout << "- Kích thước nhỏ (vài MB)" << endl;
    cout << "- Tự động dọn dẹp" << endl;
    cout << "- Nhanh" << endl;
    cout << "- Biến local, tham số" << endl;
    cout << endl;

    cout << "HEAP:" << endl;
    cout << "- Kích thước lớn (GB)" << endl;
    cout << "- Phải dọn thủ công (new/delete)" << endl;
    cout << "- Chậm hơn" << endl;
    cout << "- Dữ liệu động, lớn" << endl;
    cout << endl;

    cout << "Khi nào dùng Heap?" << endl;
    cout << "- Kích thước không biết trước" << endl;
    cout << "- Dữ liệu cần sống lâu" << endl;
    cout << "- Dữ liệu quá lớn cho Stack" << endl;

    return 0;
}

