// delete: Giải phóng bộ nhớ Heap

#include <iostream>
using namespace std;

int main() {
    cout << "=== TOÁN TỬ DELETE ===" << endl;
    cout << endl;

    // Cấp phát và giải phóng
    int* ptr = new int(100);
    cout << "Sau new: *ptr = " << *ptr << endl;

    delete ptr;  // Giải phóng
    cout << "Đã delete ptr" << endl;

    // Đặt về nullptr sau delete (best practice)
    ptr = nullptr;
    cout << endl;

    // Với mảng
    int* arr = new int[5];
    for (int i = 0; i < 5; i++) {
        arr[i] = i;
    }

    delete[] arr;  // Phải dùng delete[] cho mảng!
    arr = nullptr;
    cout << "Đã delete[] arr" << endl;
    cout << endl;

    cout << "Quy tắc vàng:" << endl;
    cout << "1. Mỗi new phải có 1 delete" << endl;
    cout << "2. Mảng dùng delete[], không phải delete" << endl;
    cout << "3. Sau delete, đặt ptr = nullptr" << endl;
    cout << "4. Không delete 2 lần!" << endl;
    cout << endl;

    cout << "Lỗi phổ biến:" << endl;
    cout << "- Quên delete -> Memory leak" << endl;
    cout << "- Delete 2 lần -> Crash" << endl;
    cout << "- Dùng delete thay vì delete[] -> Undefined behavior" << endl;

    return 0;
}

