// Smart Pointers: Tự động delete

#include <iostream>
#include <memory>  // unique_ptr, shared_ptr
using namespace std;

int main() {
    cout << "=== SMART POINTERS ===" << endl;
    cout << endl;

    // unique_ptr: Chỉ 1 owner
    {
        unique_ptr<int> ptr = make_unique<int>(42);
        cout << "unique_ptr: " << *ptr << endl;
        // Tự động delete khi ra khỏi scope!
    }
    cout << "unique_ptr đã tự động delete" << endl;
    cout << endl;

    // Với mảng
    {
        unique_ptr<int[]> arr = make_unique<int[]>(5);
        for (int i = 0; i < 5; i++) {
            arr[i] = i * 10;
        }
        cout << "arr[2] = " << arr[2] << endl;
        // Tự động delete[]
    }
    cout << "Mảng đã tự động delete[]" << endl;
    cout << endl;

    cout << "Ưu điểm Smart Pointers:" << endl;
    cout << "- Không cần delete thủ công" << endl;
    cout << "- Không bao giờ memory leak" << endl;
    cout << "- Exception safe" << endl;
    cout << "- Code sạch hơn" << endl;
    cout << endl;

    cout << "Quy tắc C++ hiện đại:" << endl;
    cout << "Ưu tiên: unique_ptr > raw pointer" << endl;
    cout << "Chỉ dùng raw pointer khi thật sự cần" << endl;

    return 0;
}

