// class: struct + methods + encapsulation

#include <iostream>
#include <string>
using namespace std;

class BankAccount {
private:  // Giấu dữ liệu
    double balance;

public:   // Interface công khai
    BankAccount(double initial) {
        balance = initial;
    }

    void deposit(double amount) {
        if (amount > 0) {
            balance += amount;
            cout << "Nạp " << amount << " thành công" << endl;
        }
    }

    void withdraw(double amount) {
        if (amount > 0 && amount <= balance) {
            balance -= amount;
            cout << "Rút " << amount << " thành công" << endl;
        } else {
            cout << "Không đủ tiền!" << endl;
        }
    }

    double getBalance() {
        return balance;
    }
};

int main() {
    cout << "=== CLASS & ENCAPSULATION ===" << endl;
    cout << endl;

    BankAccount acc(1000);

    cout << "Số dư ban đầu: " << acc.getBalance() << endl;
    acc.deposit(500);
    cout << "Số dư: " << acc.getBalance() << endl;
    acc.withdraw(300);
    cout << "Số dư: " << acc.getBalance() << endl;
    cout << endl;

    // acc.balance = 999999;  // ❌ Lỗi: private!

    cout << "Encapsulation:" << endl;
    cout << "- Giấu dữ liệu (private)" << endl;
    cout << "- Chỉ cho phép truy cập qua method" << endl;
    cout << "- Bảo vệ dữ liệu khỏi thay đổi sai" << endl;

    return 0;
}

