        if (pwd.length() >= 6) {
            password = pwd;
            cout << "Đặt mật khẩu thành công" << endl;
        } else {
            cout << "Mật khẩu quá ngắn!" << endl;
        }
    }

    bool checkPassword(string pwd) {
        return password == pwd;
    }
};

