    p.age = 25;
    cout << "Tên: " << p.name << endl;
    cout << "Tuổi: " << p.age << endl;
    cout << endl;

    // private: Chỉ qua method
    p.setPassword("123");      // Quá ngắn
    p.setPassword("secret123"); // OK
    cout << "Kiểm tra mật khẩu: " << p.checkPassword("secret123") << endl;
    cout << endl;

    // p.password = "hack";  // ❌ Lỗi: private!

    cout << "Quy tắc:" << endl;
    cout << "- Dữ liệu: private" << endl;
    cout << "- Method: public" << endl;
    cout << "- Helper method: private" << endl;

    return 0;
}

