        delete[] data;  // Tự động dọn dẹp!
        cout << "Đóng file: " << filename << endl;
    }

    void process() {
        cout << "Xử lý file: " << filename << endl;
    }
};

int main() {
    cout << "=== DESTRUCTOR & RAII ===" << endl;
    cout << endl;

    {
        FileHandler file("data.txt");
        file.process();
        // Destructor tự động gọi khi ra khỏi scope!
    }

    cout << endl;
    cout << "RAII (Resource Acquisition Is Initialization):" << endl;
    cout << "- Constructor: Xin tài nguyên" << endl;
    cout << "- Destructor: Trả lại tài nguyên" << endl;
    cout << "- Tự động, không cần nhớ" << endl;
    cout << "- Không bao giờ leak!" << endl;
    cout << endl;

    cout << "Ứng dụng RAII:" << endl;
    cout << "- File handling" << endl;
    cout << "- Memory management" << endl;
    cout << "- Lock/Mutex" << endl;
    cout << "- Database connection" << endl;

    return 0;
}

